use std::collections::HashMap;
use serde::{Serialize, Deserialize};

#[derive(Debug, Serialize, Deserialize)]
struct UserProfile {
    user_id: u64,
    username: String,
}

#[derive(Debug, Serialize, Deserialize)]
struct TaskRecord {
    task_id: u32,
    description: String,
    is_completed: bool,
}

trait ApiObject {
    fn get_identifier(&self) -> Box<dyn std::any::Any + Send + Sync>;
    fn to_string_representation(&self) -> String;
}
impl ApiObject for UserProfile {
    fn get_identifier(&self) -> Box<dyn std::any::Any + Send + Sync> {
        Box::new(self.user_id)
    }
    fn to_string_representation(&self) -> String {
        format!("User: {}", self.username)
    }
}
impl ApiObject for TaskRecord {
    fn get_identifier(&self) -> Box<dyn std::any::Any + Send + Sync> {
        Box::new(self.task_id)
    }
    fn to_string_representation(&self) -> String {
        format!("Task ID: {}", self.task_id)
    }
}

fn process_generic_objects<T: ApiObject + 'static>(object: &T) -> String {
    let id = object.get_identifier();
    let representation = object.to_string_representation();
    format!("Processed Object - ID Type {:?}, Representation: {}", std::any::type_name::<T>(), representation)
}

fn main() {
    let profile = UserProfile { user_id: 101, username: "jdoe".to_string() };
    let task = TaskRecord { task_id: 5, description: "Write API endpoint".to_string(), is_completed: false };

    let result1 = process_generic_objects(&profile);
    let result2 = process_generic_objects(&task);

    println!("{}", result1);
    println!("{}", result2);
}

use std::fmt::{self, Display};
use serde::{Serialize, Deserialize};
use std::collections::HashMap;

trait JsonSerializable {
    fn serialize_to_map(&self) -> Result<HashMap<String, String>, String>;
}

struct TaskManagerPayload {
    user_id: u32,
    task_name: String,
    due_date: String,
}

impl JsonSerializable for TaskManagerPayload {
    fn serialize_to_map(&self) -> Result<HashMap<String, String>, String> {
        let mut map = HashMap::new();
        map.insert("user_id".to_string(), self.user_id.to_string());
        map.insert("task_name".to_string(), self.task_name.clone());
        map.insert("due_date".to_string(), self.due_date.clone());
        Ok(map)
    }
}

fn process_generic_data<T: JsonSerializable>(data: &T) -> Result<HashMap<String, String>, String> {
    data.serialize_to_map()
}

fn main() {
    let task = TaskManagerPayload {
        user_id: 101,
        task_name: String::from("Write API spec"),
        due_date: String::from("2024-12-31"),
    };

    match process_generic_data(&task) {
        Ok(payload) => {
            println!("Successfully processed payload:");
            for (key, value) in payload {
                println!("  {}: {}", key, value);
            }
        }
        Err(e) => {
            eprintln!("Failed to process data: {}", e);
        }
    }
}
